    type ReportRefund'Outcome = | Refunded

    type ReportRefund'ProcessorDetailsCustom =
        {
            /// A reference to the external refund. This field must be unique across all refunds.
            [<Config.Form>]
            RefundReference: string option
        }

    type ReportRefund'ProcessorDetailsCustom with
        static member New(?refundReference: string) =
            {
                RefundReference = refundReference
            }

    type ReportRefund'ProcessorDetailsType = | Custom

    type ReportRefund'ProcessorDetails =
        {
            /// Information about the custom processor used to make this refund.
            [<Config.Form>]
            Custom: ReportRefund'ProcessorDetailsCustom option
            /// The type of the processor details. An additional hash is included on processor_details with a name matching this value. It contains additional information specific to the processor.
            [<Config.Form>]
            Type: ReportRefund'ProcessorDetailsType option
        }

    type ReportRefund'ProcessorDetails with
        static member New(?custom: ReportRefund'ProcessorDetailsCustom, ?type': ReportRefund'ProcessorDetailsType) =
            {
                Custom = custom
                Type = type'
            }

    type ReportRefund'Refunded =
        {
            /// When the reported refund completed. Measured in seconds since the Unix epoch.
            [<Config.Form>]
            RefundedAt: DateTime option
        }

    type ReportRefund'Refunded with
        static member New(?refundedAt: DateTime) =
            {
                RefundedAt = refundedAt
            }

    type ReportRefundOptions =
        {
            /// The ID of the Payment Record.
            [<Config.Path>]
            Id: string
            /// A positive integer in the [smallest currency unit](https://docs.stripe.com/currencies#zero-decimal) representing how much of this payment to refund. Can refund only up to the remaining, unrefunded amount of the payment.
            [<Config.Form>]
            Amount: ReportRefund'Amount option
            /// Specifies which fields in the response should be expanded.
            [<Config.Form>]
            Expand: string list option
            /// When the reported refund was initiated. Measured in seconds since the Unix epoch.
            [<Config.Form>]
            InitiatedAt: DateTime option
            /// Set of [key-value pairs](https://docs.stripe.com/api/metadata) that you can attach to an object. This can be useful for storing additional information about the object in a structured format. Individual keys can be unset by posting an empty value to them. All keys can be unset by posting an empty value to `metadata`.
            [<Config.Form>]
            Metadata: Map<string, string> option
            /// The outcome of the reported refund.
            [<Config.Form>]
            Outcome: ReportRefund'Outcome
            /// Processor information for this refund.
            [<Config.Form>]
            ProcessorDetails: ReportRefund'ProcessorDetails
            /// Information about the payment attempt refund.
            [<Config.Form>]
            Refunded: ReportRefund'Refunded
        }

    type ReportRefundOptions with
        static member New(id: string, outcome: ReportRefund'Outcome, processorDetails: ReportRefund'ProcessorDetails, refunded: ReportRefund'Refunded, ?amount: ReportRefund'Amount, ?expand: string list, ?initiatedAt: DateTime, ?metadata: Map<string, string>) =
            {
                Id = id
                Outcome = outcome
                ProcessorDetails = processorDetails
                Refunded = refunded
                Amount = amount
                Expand = expand
                InitiatedAt = initiatedAt
                Metadata = metadata
            }

    ///<p>Report that the most recent payment attempt on the specified Payment Record
    /// was refunded.</p>
    let ReportRefund settings (options: ReportRefundOptions) =
        $"/v1/payment_records/{options.Id}/report_refund"
        |> RestApi.postAsync<_, PaymentRecord> settings (Map.empty) options

